function linkMore(n){const i=1*n.getAttribute("page"),r=n.getAttribute("child-type"),u=n.getAttribute("data-recipient"),f=t=>{var r,f;if(n.setAttribute("page",i+1),r=t?t.trim():t,r&&r.length>0){const t=document.createElement("div");t.innerHTML=r;const i=t.childNodes[0];document.getElementById(u).appendChild(i);f=i.getAttribute("hasMore");f!="True"&&n.setAttribute("style","display: none")}else n.setAttribute("style","display: none")},t=new XMLHttpRequest;return t.onreadystatechange=function(){t.readyState==4&&f(t.responseText)},t.open("GET",window.location.href+"/"+r+"?page="+i),t.send(),!1}